func main() {
	log.SetFlags(0)
	err := commands.Execute(os.Args[1:])
	if err != nil {
		for _, e := range herrors.Errors(err) {
			loggers.Log().Errorf("%s", e)
		}
		os.Exit(1)
	}
}

